sql:
SELECT classroom_name, capacity, SQRT(capacity) AS sqrt_capacity
FROM classrooms
WHERE capacity > 20;

SELECT COUNT(DISTINCT student_id) AS active_students_count
FROM enrollments
WHERE enrollment_status = 'active';

